prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(CONTAINS(STR(?normId), "0ae2e7d8093840cc8a65c475b6275cae") || CONTAINS(STR(?origId), "0ae2e7d8093840cc8a65c475b6275cae"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?gatewayDir ?defaultFlow WHERE {
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_d8d3781e_3b5a_4864_8c2e_da05b5b75a2b> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?gatewayDir . }
  OPTIONAL { ?gateway bboExt:default ?defaultFlow . }
}
LIMIT 10
